const employeeId = $('Webhook').first().json.body.employeeId;
const month = Number($('Webhook').first().json.body.month);
const year = Number($('Webhook').first().json.body.year);

const rows = $input.all();

// Filter rows for employee + month + year
const records = rows.filter(item => {
  const row = item.json;

  if (row.employeeId !== employeeId) return false;

  const d = new Date(row.date);

  return (
    d.getFullYear() === year &&
    (d.getMonth() + 1) === month
  );
});

// Total Present Days
const presentDays = records.length;

// Calculate Total Working Minutes
let totalMinutes = 0;

for (const record of records) {
  const wh = record.json.workingHours || "0h 0m";

  const match = wh.match(/(\d+)h\s*(\d+)m/);

  if (match) {
    totalMinutes += Number(match[1]) * 60 + Number(match[2]);
  }
}

const totalHours = Math.floor(totalMinutes / 60);
const remainingMinutes = totalMinutes % 60;

// Average
const avgMinutes = presentDays ? Math.floor(totalMinutes / presentDays) : 0;
const avgHours = Math.floor(avgMinutes / 60);
const avgRemainingMinutes = avgMinutes % 60;

return [
  {
    json: {
      employeeId,
      employeeName: records.length ? records[0].json.employeeName : "",
      month,
      year,
      presentDays,
      totalWorkingHours: `${totalHours}h ${remainingMinutes}m`,
      averageWorkingHours: `${avgHours}h ${avgRemainingMinutes}m`
    }
  }
];
